mapper.select:
SELECT SUM(IFNULL(c.social_security,0) + IFNULL(c.provident_fund,0)) socialSecurity, SUM(IFNULL(c.evection_cost,0)) evectionAmount, SUM(IFNULL(c.wages,0) + IFNULL(c.commission,0)) personnelSalary, SUM(IFNULL(c.total_cost,0)) operatingCosts FROM t_rpt_base_cost c
and c.base_date IN
#{var}
and c.match_user_id IN
#{var}

SELECT SUM(IFNULL(r.sell_total_amount,0)) as totalAmount, SUM(IFNULL(r.deal_number,0)) as totalNumber, SUM(IFNULL(r.sell_total_amount,0) - IFNULL(r.buy_total_amount,0) - IFNULL(r.transport_amount,0) - IFNULL(r.warehouse_amount,0) - IFNULL(r.steve_dorage_amount,0) - IFNULL(r.delivery_fee,0) ) as grossProfit, SUM(IFNULL(r.financial_service_amount,0)) as capitalCost FROM t_ctr_contract_settlement r LEFT JOIN t_ctr_contract s ON r.sell_contract_id = s.id LEFT JOIN t_ctr_contract b ON r.buy_contract_id = b.id WHERE r.enable_flg = TRUE and r.business_type = 'ZY-BB' and s.seal_flg = TRUE and b.seal_flg = TRUE
and r.match_credit_flg = #{matchCreditFlg}
and r.dept_id IN
#{var}
AND DATE_FORMAT(s.seal_date, '%Y-%m-%d') >= DATE_FORMAT(#{sealStartDate}, '%Y-%m-%d')
AND DATE_FORMAT(s.seal_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{sealEndDate}, '%Y-%m-%d'),INTERVAL 1 DAY)

SELECT
SUM(IFNULL(w.target_total_amount,0)) targetTotalAmount
FROM work_target w


		and w.target_month IN

			#{var}



		and w.branch_cd IN

			#{var}



		and w.target_type = #{targetType}

select t1.recruitmentCosts, t2.trainingCosts, t3.rentPropertyCosts, t4.officeCosts, t5.businessEntertainmentCosts
from (SELECT SUM(IFNULL(bp.deal_amount,0)) recruitmentCosts FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id
bp.status = 'D' AND process_code = 'APPLY_MANAGE_BUSINESS_PAY' AND bp.cost_type = '22'
and bp.dept_id IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t1, (SELECT SUM(IFNULL(bp.deal_amount,0)) trainingCosts FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id
bp.status = 'D' AND process_code = 'APPLY_MANAGE_BUSINESS_PAY' AND bp.cost_type = '23'
and bp.dept_id IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t2, ( SELECT IFNULL(t31.rentPropertyCosts1, 0) + IFNULL(t32.rentPropertyCosts2, 0) AS rentPropertyCosts FROM ( SELECT SUM(IFNULL(bp.deal_amount,0)) AS rentPropertyCosts1 FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id WHERE bp.status = 'D' AND pp.process_code = 'APPLY_MANAGE_BUSINESS_PAY' AND bp.cost_type IN ('4','5','6')
and bp.apply_user_id IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t31, ( SELECT SUM(IFNULL(bp.deal_amount,0)) AS rentPropertyCosts2 FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id WHERE bp.status = 'D' AND pp.process_code = 'APPLY_OPERATING_BUSINESS_PAY' AND bp.cost_type IN ('5','18','23')
and bp.apply_user_id IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t32 ) t3, ( SELECT IFNULL(t41.officeCosts1, 0) + IFNULL(t42.officeCosts2, 0) AS officeCosts FROM ( SELECT SUM(IFNULL(bp.deal_amount,0)) AS officeCosts1 FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id WHERE bp.status = 'D' AND pp.process_code = 'APPLY_MANAGE_BUSINESS_PAY' AND bp.cost_type IN ('7','8')
and bp.dept_id IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t41, ( SELECT SUM(IFNULL(bp.deal_amount,0)) AS officeCosts2 FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id WHERE bp.status = 'D' AND pp.process_code = 'APPLY_OPERATING_BUSINESS_PAY' AND bp.cost_type IN ('19','20')
and bp.dept_id IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t42 ) t4, ( SELECT IFNULL(t51.businessEntertainmentCosts1, 0) + IFNULL(t52.businessEntertainmentCosts2, 0) AS businessEntertainmentCosts FROM ( SELECT SUM(IFNULL(bp.deal_amount,0)) AS businessEntertainmentCosts1 FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id WHERE bp.status = 'D' AND pp.process_code = 'APPLY_MANAGE_BUSINESS_PAY' AND bp.cost_type IN ('12','13')
and bp.dept_id IN
#{var}
and bp.apply_user_id NOT IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t51, ( SELECT SUM(IFNULL(bp.deal_amount,0)) AS businessEntertainmentCosts2 FROM t_apply_business_pay bp LEFT JOIN t_pm_approve pa ON pa.id = bp.approve_id LEFT JOIN t_pm_process pp ON pp.id = pa.process_id WHERE bp.status = 'D' AND pp.process_code = 'APPLY_OPERATING_BUSINESS_PAY' AND bp.cost_type IN ('6','8','21')
and bp.dept_id IN
#{var}
and bp.apply_user_id NOT IN
#{var}
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') >= DATE_FORMAT(#{startDate}, '%Y-%m-%d')
AND DATE_FORMAT(bp.request_pay_date, '%Y-%m-%d') <= DATE_ADD(DATE_FORMAT(#{endDate}, '%Y-%m-%d'),INTERVAL 1 DAY)
) t52 ) t5
